#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long X;
        scanf("%d %lld", &N, &X);
        int ans = 0;
        for (int i = 1; i <= N; ++i) {
            long long a;
            scanf("%lld", &a);
            if (a < X) ans = i;
        }
        printf("%d\n", ans);
    }
    return 0;
}

